import React, { useState, useEffect } from 'react';
import { db } from '../../firebase';
import {
    collection, onSnapshot, query, where,
    doc, addDoc, deleteDoc, updateDoc
} from 'firebase/firestore';
import { styles, tokens } from '../../styles';

const EmployeeInsight = ({ employee, onBack, isAdmin }) => {
    const [attendance, setAttendance] = useState([]);
    const [leaves, setLeaves] = useState([]);
    const [documents, setDocuments] = useState([]);
    const [showAddDoc, setShowAddDoc] = useState(false);
    const [newDoc, setNewDoc] = useState({ name: '', url: '', size: '' });
    const [savingDoc, setSavingDoc] = useState(false);
    const [editingSalary, setEditingSalary] = useState(false);
    const [salaryInput, setSalaryInput] = useState(employee.salary || '');
    const [savingSalary, setSavingSalary] = useState(false);

    useEffect(() => {
        let isMounted = true;

        const qAtt = query(collection(db, 'attendance'), where('userEmail', '==', employee.email));
        const unsubAtt = onSnapshot(qAtt, s => {
            if (!isMounted) return;
            setAttendance(s.docs.map(d => ({ id: d.id, ...d.data() })).sort((a, b) => (b.timestamp?.seconds || 0) - (a.timestamp?.seconds || 0)));
        }, err => { if (!isMounted) return; console.error(err); });

        const qLea = query(collection(db, 'leaveRequests'), where('userEmail', '==', employee.email));
        const unsubLea = onSnapshot(qLea, s => {
            if (!isMounted) return;
            setLeaves(s.docs.map(d => ({ id: d.id, ...d.data() })));
        }, err => { if (!isMounted) return; console.error(err); });

        // Load documents from subcollection
        const unsubDocs = onSnapshot(collection(db, 'employees', employee.id, 'documents'), s => {
            if (!isMounted) return;
            setDocuments(s.docs.map(d => ({ id: d.id, ...d.data() })));
        }, err => { if (!isMounted) return; console.error(err); });

        return () => { isMounted = false; unsubAtt(); unsubLea(); unsubDocs(); };
    }, [employee.email, employee.id]);

    const calculateStats = () => {
        const daily = {};
        attendance.forEach(a => {
            if (!daily[a.date]) daily[a.date] = {};
            daily[a.date][a.type] = a.timestamp?.toDate();
        });
        let totalHours = 0, counts = 0;
        Object.values(daily).forEach(day => {
            if (day.in && day.out) { totalHours += (day.out - day.in) / (1000 * 60 * 60); counts++; }
        });
        return { avg: counts > 0 ? (totalHours / counts).toFixed(1) : 0, punctuality: 98 };
    };

    const stats = calculateStats();
    const approvedLeaves = leaves.filter(l => l.status === 'approved').length;
    const initials = employee.name?.split(' ').map(n => n[0]).join('').slice(0, 2).toUpperCase() || '?';
    const nextPayout = () => {
        const d = new Date(); d.setMonth(d.getMonth() + 1, 1);
        return d.toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' });
    };

    const handleAddDocument = async () => {
        if (!newDoc.name.trim()) return;
        setSavingDoc(true);
        try {
            await addDoc(collection(db, 'employees', employee.id, 'documents'), {
                name: newDoc.name.trim(),
                url: newDoc.url.trim(),
                size: newDoc.size.trim() || '—',
                uploadedAt: new Date().toISOString(),
            });
            setNewDoc({ name: '', url: '', size: '' });
            setShowAddDoc(false);
        } catch (e) { console.error(e); }
        setSavingDoc(false);
    };

    const handleDeleteDocument = async (docId) => {
        if (!window.confirm('Remove this document?')) return;
        try { await deleteDoc(doc(db, 'employees', employee.id, 'documents', docId)); } catch (e) { console.error(e); }
    };

    const handleSaveSalary = async () => {
        setSavingSalary(true);
        try {
            await updateDoc(doc(db, 'employees', employee.id), { salary: salaryInput });
            setEditingSalary(false);
        } catch (e) { console.error(e); }
        setSavingSalary(false);
    };

    const statCards = [
        { label: 'Avg. Daily Hours', value: `${stats.avg}h`, sub: 'Target: 8.0h', subColor: tokens.colors.accent, icon: 'schedule', color: '#3B82F6', bg: '#EFF6FF' },
        { label: 'Punctuality Score', value: `${stats.punctuality}%`, sub: 'Elite Performance', subColor: '#059669', icon: 'emoji_events', color: '#059669', bg: '#ECFDF5' },
        {
            label: 'Monthly Salary', value: `$${Number(salaryInput || 0).toLocaleString()}`,
            sub: `Next Payout: ${nextPayout()}`, subColor: tokens.colors.secondary,
            icon: 'payments', color: '#8B5CF6', bg: '#F5F3FF',
        },
        { label: 'Leave Utilization', value: String(approvedLeaves), sub: 'Days used this year', subColor: '#D97706', icon: 'beach_access', color: '#F97316', bg: '#FFF7ED' },
    ];

    return (
        <div className="animate-fade">

            {/* ── Hero Header ── */}
            <div style={{
                background: 'linear-gradient(135deg, #0F172A 0%, #1E293B 60%, #134E4A 100%)',
                borderRadius: tokens.radius.xl, padding: '32px 36px', marginBottom: '28px',
                display: 'flex', alignItems: 'center', gap: '24px', position: 'relative', overflow: 'hidden',
            }}>
                <div style={{ position: 'absolute', top: '-40px', right: '80px', width: '200px', height: '200px', borderRadius: '50%', background: 'rgba(13,148,136,0.08)' }} />
                <div style={{ position: 'absolute', bottom: '-30px', right: '-20px', width: '160px', height: '160px', borderRadius: '50%', background: 'rgba(13,148,136,0.05)' }} />
                <button onClick={onBack} style={{ background: 'rgba(255,255,255,0.1)', border: '1px solid rgba(255,255,255,0.15)', borderRadius: '50%', width: '40px', height: '40px', cursor: 'pointer', flexShrink: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff' }}
                    onMouseOver={e => e.currentTarget.style.background = 'rgba(255,255,255,0.18)'}
                    onMouseOut={e => e.currentTarget.style.background = 'rgba(255,255,255,0.1)'}
                >
                    <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>arrow_back</span>
                </button>
                <div style={{ width: '72px', height: '72px', borderRadius: '20px', flexShrink: 0, background: 'linear-gradient(135deg, #0D9488 0%, #0F766E 100%)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '26px', fontWeight: '800', color: '#CCFBF1', border: '2px solid rgba(255,255,255,0.15)', boxShadow: '0 8px 24px -8px rgba(13,148,136,0.5)' }}>{initials}</div>
                <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: '24px', fontWeight: '800', color: '#fff', letterSpacing: '-0.02em', marginBottom: '6px' }}>{employee.name}</div>
                    <div style={{ display: 'flex', alignItems: 'center', flexWrap: 'wrap', gap: '8px' }}>
                        <span style={{ fontSize: '13px', background: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.75)', padding: '4px 12px', borderRadius: '999px', fontWeight: '600' }}>{employee.role}</span>
                        <span style={{ color: 'rgba(255,255,255,0.3)', fontSize: '12px' }}>·</span>
                        <span style={{ fontSize: '13px', background: 'rgba(13,148,136,0.2)', color: '#5EEAD4', padding: '4px 12px', borderRadius: '999px', fontWeight: '600' }}>{employee.dept}</span>
                        <span style={{ fontSize: '13px', background: employee.profileComplete ? 'rgba(16,185,129,0.15)' : 'rgba(239,68,68,0.15)', color: employee.profileComplete ? '#34D399' : '#F87171', padding: '4px 12px', borderRadius: '999px', fontWeight: '600' }}>
                            {employee.profileComplete ? '● Active' : '○ Pending Setup'}
                        </span>
                    </div>
                    {employee.email && <div style={{ marginTop: '8px', fontSize: '13px', color: 'rgba(255,255,255,0.45)', display: 'flex', alignItems: 'center', gap: '6px' }}><span className="material-symbols-outlined" style={{ fontSize: '14px' }}>mail</span>{employee.email}</div>}
                </div>
                <div style={{ textAlign: 'right', flexShrink: 0 }}>
                    <div style={{ fontSize: '11px', color: 'rgba(255,255,255,0.4)', fontWeight: '700', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '4px' }}>Emp ID</div>
                    <div style={{ fontSize: '14px', fontWeight: '800', color: 'rgba(255,255,255,0.7)', fontFamily: 'monospace', letterSpacing: '0.05em' }}>{employee.id?.slice(0, 8).toUpperCase()}</div>
                </div>
            </div>

            {/* ── Stat Cards ── */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '16px', marginBottom: '28px' }}>
                {statCards.map((s, i) => (
                    <div key={i} style={{ ...styles.card, padding: '20px 24px', borderLeft: `3px solid ${s.color}` }}>
                        <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', marginBottom: '12px' }}>
                            <div style={{ fontSize: '12px', fontWeight: '700', color: tokens.colors.secondary, textTransform: 'uppercase', letterSpacing: '0.06em' }}>{s.label}</div>
                            <div style={{ width: '32px', height: '32px', borderRadius: '10px', background: s.bg, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                                <span className="material-symbols-outlined" style={{ fontSize: '16px', color: s.color }}>{s.icon}</span>
                            </div>
                        </div>
                        <div style={{ fontSize: '28px', fontWeight: '800', color: tokens.colors.primary, letterSpacing: '-0.02em', marginBottom: '8px' }}>{s.value}</div>
                        <div style={{ fontSize: '12px', fontWeight: '600', color: s.subColor }}>{s.sub}</div>
                    </div>
                ))}
            </div>

            {/* ── Bottom Grid ── */}
            <div style={{ display: 'grid', gridTemplateColumns: '1.5fr 1fr', gap: '24px' }}>

                {/* Timesheet */}
                <div style={styles.card}>
                    <h3 style={{ fontSize: '16px', fontWeight: '800', color: tokens.colors.primary, marginBottom: '20px', display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <span className="material-symbols-outlined" style={{ fontSize: '18px', color: tokens.colors.accent }}>receipt_long</span>
                        Recent Timesheet Activity
                    </h3>
                    <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                        <thead>
                            <tr>
                                <th style={styles.th}>Date</th>
                                <th style={styles.th}>Event</th>
                                <th style={styles.th}>Time</th>
                                <th style={{ ...styles.th, textAlign: 'right' }}>Status</th>
                            </tr>
                        </thead>
                        <tbody>
                            {attendance.slice(0, 8).map(log => (
                                <tr key={log.id}>
                                    <td style={{ ...styles.td, fontSize: '13px', color: tokens.colors.secondary }}>{log.date || '—'}</td>
                                    <td style={styles.td}>
                                        <div style={{ display: 'inline-flex', alignItems: 'center', gap: '6px' }}>
                                            <span style={{ width: '8px', height: '8px', borderRadius: '50%', flexShrink: 0, background: log.type === 'in' ? '#10B981' : '#EF4444' }} />
                                            <span style={{ fontSize: '12px', fontWeight: '800', letterSpacing: '0.04em', color: log.type === 'in' ? '#059669' : '#DC2626' }}>{log.type === 'in' ? 'CLOCK IN' : 'CLOCK OUT'}</span>
                                        </div>
                                    </td>
                                    <td style={{ ...styles.td, fontSize: '13px', fontWeight: '600' }}>{log.timeString || '—'}</td>
                                    <td style={{ ...styles.td, textAlign: 'right' }}>
                                        <span style={{ fontSize: '11px', fontWeight: '700', background: '#ECFDF5', color: '#059669', padding: '3px 10px', borderRadius: '999px' }}>Verified</span>
                                    </td>
                                </tr>
                            ))}
                            {attendance.length === 0 && <tr><td colSpan="4" style={{ textAlign: 'center', padding: '40px', color: tokens.colors.secondary, fontSize: '14px' }}>No attendance logs found.</td></tr>}
                        </tbody>
                    </table>
                </div>

                {/* Right column */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>

                    {/* Salary Management (admin only) */}
                    {isAdmin && (
                        <div style={styles.card}>
                            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '16px' }}>
                                <h3 style={{ fontSize: '16px', fontWeight: '800', color: tokens.colors.primary, display: 'flex', alignItems: 'center', gap: '8px' }}>
                                    <span className="material-symbols-outlined" style={{ fontSize: '18px', color: '#8B5CF6' }}>payments</span>
                                    Compensation
                                </h3>
                                {!editingSalary && (
                                    <button onClick={() => setEditingSalary(true)} style={{ ...styles.button.outline, padding: '6px 14px', fontSize: '12px' }}>
                                        <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>edit</span> Edit
                                    </button>
                                )}
                            </div>
                            {editingSalary ? (
                                <div>
                                    <label style={{ fontSize: '12px', fontWeight: '700', color: tokens.colors.secondary, display: 'block', marginBottom: '8px', textTransform: 'uppercase', letterSpacing: '0.05em' }}>Monthly Salary (USD)</label>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                                        <div style={{ position: 'relative', flex: 1 }}>
                                            <span style={{ position: 'absolute', left: '14px', top: '50%', transform: 'translateY(-50%)', fontWeight: '700', color: tokens.colors.secondary }}>$</span>
                                            <input type="number" min="0" style={{ ...styles.input, paddingLeft: '28px' }} value={salaryInput} onChange={e => setSalaryInput(e.target.value)} placeholder="0" />
                                        </div>
                                        <button onClick={handleSaveSalary} disabled={savingSalary} style={{ ...styles.button.primary, padding: '10px 16px', fontSize: '13px', flexShrink: 0 }}>
                                            {savingSalary ? 'Saving…' : 'Save'}
                                        </button>
                                        <button onClick={() => { setEditingSalary(false); setSalaryInput(employee.salary || ''); }} style={{ ...styles.button.outline, padding: '10px 16px', fontSize: '13px', flexShrink: 0 }}>Cancel</button>
                                    </div>
                                </div>
                            ) : (
                                <div style={{ display: 'flex', alignItems: 'baseline', gap: '6px' }}>
                                    <span style={{ fontSize: '32px', fontWeight: '800', color: tokens.colors.primary, letterSpacing: '-0.02em' }}>${Number(salaryInput || 0).toLocaleString()}</span>
                                    <span style={{ fontSize: '13px', color: tokens.colors.secondary, fontWeight: '600' }}>/ month</span>
                                </div>
                            )}
                            <div style={{ marginTop: '12px', fontSize: '12px', background: '#F5F3FF', color: '#7C3AED', padding: '8px 12px', borderRadius: '8px', fontWeight: '600' }}>
                                Next payout: {nextPayout()}
                            </div>
                        </div>
                    )}

                    {/* Leave Summary */}
                    <div style={styles.card}>
                        <h3 style={{ fontSize: '16px', fontWeight: '800', color: tokens.colors.primary, marginBottom: '16px', display: 'flex', alignItems: 'center', gap: '8px' }}>
                            <span className="material-symbols-outlined" style={{ fontSize: '18px', color: '#F97316' }}>event_available</span>
                            Leave Summary
                        </h3>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                            {[
                                { label: 'Pending', count: leaves.filter(l => l.status === 'pending').length, color: '#D97706', bg: '#FFFBEB' },
                                { label: 'Approved', count: leaves.filter(l => l.status === 'approved').length, color: '#059669', bg: '#ECFDF5' },
                                { label: 'Rejected', count: leaves.filter(l => l.status === 'rejected').length, color: '#DC2626', bg: '#FEF2F2' },
                            ].map(row => (
                                <div key={row.label} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 14px', borderRadius: '10px', background: row.bg }}>
                                    <span style={{ fontSize: '13px', fontWeight: '600', color: row.color }}>{row.label}</span>
                                    <span style={{ fontSize: '18px', fontWeight: '800', color: row.color }}>{row.count}</span>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Employment Documents */}
                    <div style={styles.card}>
                        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '16px' }}>
                            <h3 style={{ fontSize: '16px', fontWeight: '800', color: tokens.colors.primary, display: 'flex', alignItems: 'center', gap: '8px' }}>
                                <span className="material-symbols-outlined" style={{ fontSize: '18px', color: '#6366F1' }}>folder_shared</span>
                                Documents
                            </h3>
                            {isAdmin && (
                                <button onClick={() => setShowAddDoc(o => !o)} style={{ ...styles.button.primary, padding: '6px 14px', fontSize: '12px' }}>
                                    <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>{showAddDoc ? 'close' : 'upload_file'}</span>
                                    {showAddDoc ? 'Cancel' : 'Add'}
                                </button>
                            )}
                        </div>

                        {/* Add document form (admin only) */}
                        {isAdmin && showAddDoc && (
                            <div style={{ marginBottom: '16px', padding: '16px', background: '#F8FAFC', borderRadius: '12px', border: `1px solid ${tokens.colors.border}` }}>
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                                    <div>
                                        <label style={{ fontSize: '11px', fontWeight: '700', color: tokens.colors.secondary, display: 'block', marginBottom: '5px', textTransform: 'uppercase', letterSpacing: '0.05em' }}>Document Name *</label>
                                        <input style={styles.input} value={newDoc.name} onChange={e => setNewDoc({ ...newDoc, name: e.target.value })} placeholder="e.g. Offer Letter.pdf" />
                                    </div>
                                    <div>
                                        <label style={{ fontSize: '11px', fontWeight: '700', color: tokens.colors.secondary, display: 'block', marginBottom: '5px', textTransform: 'uppercase', letterSpacing: '0.05em' }}>File URL (optional)</label>
                                        <input style={styles.input} value={newDoc.url} onChange={e => setNewDoc({ ...newDoc, url: e.target.value })} placeholder="https://drive.google.com/..." />
                                    </div>
                                    <div>
                                        <label style={{ fontSize: '11px', fontWeight: '700', color: tokens.colors.secondary, display: 'block', marginBottom: '5px', textTransform: 'uppercase', letterSpacing: '0.05em' }}>File Size (optional)</label>
                                        <input style={styles.input} value={newDoc.size} onChange={e => setNewDoc({ ...newDoc, size: e.target.value })} placeholder="e.g. 1.2 MB" />
                                    </div>
                                    <button onClick={handleAddDocument} disabled={savingDoc || !newDoc.name.trim()} style={{ ...styles.button.primary, width: '100%', justifyContent: 'center', padding: '10px', opacity: !newDoc.name.trim() ? 0.5 : 1 }}>
                                        <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>save</span>
                                        {savingDoc ? 'Saving…' : 'Save Document'}
                                    </button>
                                </div>
                            </div>
                        )}

                        {/* Document list */}
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                            {documents.map(d => (
                                <div key={d.id} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '12px 14px', borderRadius: '10px', border: `1px solid ${tokens.colors.border}`, background: '#FAFBFC' }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                                        <div style={{ width: '34px', height: '34px', borderRadius: '10px', background: '#EEF2FF', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                                            <span className="material-symbols-outlined" style={{ fontSize: '16px', color: '#6366F1' }}>description</span>
                                        </div>
                                        <div>
                                            <div style={{ fontSize: '13px', fontWeight: '700', color: tokens.colors.primary }}>{d.name}</div>
                                            <div style={{ fontSize: '11px', color: tokens.colors.secondary }}>{d.size}</div>
                                        </div>
                                    </div>
                                    <div style={{ display: 'flex', gap: '6px' }}>
                                        {d.url && (
                                            <a href={d.url} target="_blank" rel="noopener noreferrer" style={{ border: 'none', background: 'none', cursor: 'pointer', padding: '6px', borderRadius: '8px', color: tokens.colors.secondary, display: 'flex', alignItems: 'center', textDecoration: 'none' }}
                                                onMouseOver={e => e.currentTarget.style.background = '#F1F5F9'}
                                                onMouseOut={e => e.currentTarget.style.background = 'none'}
                                            >
                                                <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>download</span>
                                            </a>
                                        )}
                                        {isAdmin && (
                                            <button onClick={() => handleDeleteDocument(d.id)} style={{ border: 'none', background: 'none', cursor: 'pointer', padding: '6px', borderRadius: '8px', color: '#EF4444', display: 'flex', alignItems: 'center' }}
                                                onMouseOver={e => e.currentTarget.style.background = '#FEF2F2'}
                                                onMouseOut={e => e.currentTarget.style.background = 'none'}
                                            >
                                                <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>delete</span>
                                            </button>
                                        )}
                                    </div>
                                </div>
                            ))}
                            {documents.length === 0 && (
                                <div style={{ textAlign: 'center', padding: '28px 16px', color: tokens.colors.secondary, fontSize: '13px' }}>
                                    <span className="material-symbols-outlined" style={{ display: 'block', fontSize: '32px', marginBottom: '8px', color: '#CBD5E1' }}>folder_open</span>
                                    {isAdmin ? 'No documents yet. Use "Add" to upload.' : 'No documents available.'}
                                </div>
                            )}
                        </div>
                    </div>

                </div>
            </div>
        </div>
    );
};

export default EmployeeInsight;
